// PARA QUEM VAI CADA ALERTA — EDITE AQUI.
// Uma linha por unidade: qual unidade consultar e o WhatsApp do gestor que
// recebe. O número vai no formato internacional só com dígitos (55 + DDD + número).
//
// Uma linha vira um item; os nós seguintes rodam uma vez por item, então o mesmo
// fluxo cobre a rede inteira: é só adicionar unidades conforme conectam o token.
return [
  { json: { unitId: 15, unidade: 'Imperatriz', whatsapp: '5599999999999' } },
  // { json: { unitId: 7,  unidade: 'Araguaína',  whatsapp: '55639...' } },
];

// Monta o texto do alerta a partir do resumo que a API devolveu.
// Sem emojis (preferência do projeto); negrito do WhatsApp com *asteriscos*.
const r = $json;
const dest = $('Unidades e destinatários').item.json;

// Unidade sem token conectado: não envia (retorna vazio → o nó de envio pula).
if (!r.conectado) {
  return [];
}

const h = r.hoje;
const partes = [
  `*${r.unidade}* — resumo de ${r.data.split('-').reverse().join('/')}`,
  ``,
  `Avaliacoes agendadas: ${h.avaliacoesAgendadas}`,
  `Compareceram: ${h.compareceram}`,
  `Faltaram: ${h.faltaram}`,
  `Desmarcadas: ${h.desmarcadas}`,
  `Comparecimento: ${h.taxaComparecimento}%`,
];

if (r.amanha && r.amanha.avaliacoesAgendadas > 0) {
  partes.push('', `Amanha: ${r.amanha.avaliacoesAgendadas} avaliacoes agendadas.`);
}

// Linha de atenção quando houve falta ou desmarque relevante.
if (h.faltaram > 0 || h.desmarcadas >= 3) {
  partes.push('', `Atencao: ${h.faltaram} falta(s) e ${h.desmarcadas} desmarque(s) hoje.`);
}

return [{
  json: {
    number: dest.whatsapp,
    text: partes.join('\n'),
  },
}];
